mapper.select:
	/* wms-master-equipment-sql-oracle.xml - selectPkCntTWorkMstEq */
	SELECT	COUNT(1)
  	  FROM	TWORK_MST_EQ
     WHERE	EQKEY = #{eqkey}
       AND	PRTYPE = #{prtype}

 	  AND CTKEY = #{ctkey}

mapper.delete:
	/* wms-master-equipment-sql-oracle.xml - deleteTWorkMstEq */
   DELETE	
     FROM	TWORK_MST_EQ
    WHERE	EQKEY = #{eqkey}
      AND	PRTYPE = #{prtype}

 	  AND CTKEY = #{ctkey}

mapper.insert:
		/* wms-master-equipment-sql-oracle.xml - insertTWorkMstEq */
	  INSERT INTO TWORK_MST_EQ
			( 
			 CTKEY
             ,EQKEY
             ,EQTYPE
             ,IPADDRESS
             ,EQNAME
             ,CLOSDATE
             ,UPDATEURKEY
             ,UPDATEDATE             
             ,INSERTURKEY
             ,INSERTDATE
             ,PRTYPE
			)
			VALUES 
			( 
			 #{ctkey}
			 ,#{eqkey}
			 ,#{eqtype}
			 ,#{ipaddress}
			 ,#{eqname}
			 ,#{closdate}
			 ,#{surkey}
			 ,#{sysdate}
			 ,#{surkey}
			 ,#{sysdate}
			 ,#{prtype}
			)

mapper.update:
		/* wms-master-equipment-sql-oracle.xml - updateTWorkMstEq */
			UPDATE TWORK_MST_EQ 
			   SET
               		EQTYPE 				= #{eqtype}
               		,IPADDRESS 			= #{ipaddress}
               		,EQNAME 			= #{eqname}
               		,CLOSDATE 		= #{closdate}
			        ,UPDATEDATE 		= #{sysdate}
			        ,UPDATEURKEY 		= #{surkey}
			WHERE	EQKEY = #{eqkey}
			    AND PRTYPE	= #{prtype}

	 	  	AND CTKEY = #{ctkey}
